#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define N 20000001
using namespace std;
int T1,T2,T3,T4,cnt,rt[N],crt;
//define
struct FHQ{int l,r,f,val,siz,key;}t[N];
inline int read()
{
	int res=0;bool flag=0;char ch=getchar();
	while(ch<'0'||ch>'9'){if(ch=='-')flag=1;ch=getchar();}
	while(ch>='0'&&ch<='9')res=(res<<1)+(res<<3)+(ch^48),ch=getchar();
	return flag?-res:res;
}
//debug
//algortihm
inline void update(int k){t[k].siz=t[t[k].l].siz+t[t[k].r].siz+1;}
inline int new_node(int k){t[++cnt].val=k;t[cnt].siz=1;t[cnt].key=rand();return cnt;}
inline void split(int k,int cur,int &x,int &y)
{
	if(!cur){x=y=0;return;}
	else if(t[cur].val<=k)
	{
		x=++cnt;t[x]=t[cur];
		split(k,t[x].r,t[x].r,y);
		update(x);
	}
	else 
	{
		y=++cnt;t[y]=t[cur];
		split(k,t[y].l,x,t[y].l);
		update(y);
	}
}
inline int merge(int L,int R)
{
	if(!L||!R)return L+R;
	if(t[L].key>t[R].key)
	{
		t[L].r=merge(t[L].r,R);
		update(L);return L;
	}
	else
	{
		t[R].l=merge(L,t[R].l);
		update(R);return R;
	}
}
inline void ins(int Root,int k)
{
	split(k,Root,T1,T2);
	rt[++crt]=merge(merge(T1,new_node(k)),T2);
//	printf("%d %d\n",crt,rt[crt]);
	return;
}
inline void del(int Root,int k)
{
	split(k,Root,T1,T2);
	split(k-1,T1,T3,T4);
	T4=merge(t[T4].l,t[T4].r);
	rt[++crt]=merge(merge(T3,T4),T2);
	
}
int ans;
inline void dfs(int cur,int Siz)
{
//	printf("%d %d\n",cur,Siz);
	int ls=t[t[cur].l].siz;
	if(Siz>ls)dfs(t[cur].r,Siz-t[t[cur].l].siz-1);
	else if(Siz<ls)dfs(t[cur].l,Siz);
	else {ans=cur;return;}
}
inline int kth(int Root,int k)
{
	dfs(Root,k-1);rt[++crt]=Root;return t[ans].val;
}
inline int pre(int Root,int k)
{
	split(k-1,Root,T1,T2);
	int cur=T1;
	while(t[cur].r)cur=t[cur].r;
	rt[++crt]=merge(T1,T2);
	return t[cur].val;
}
inline int suc(int Root,int k)
{
	split(k,Root,T1,T2);
	int cur=T2;
	while(t[cur].l)cur=t[cur].l;
	rt[++crt]=merge(T1,T2);
	return t[cur].val;
}
inline int rnk(int Root,int k)
{
	split(k-1,Root,T1,T2);
	int res=t[T1].siz+1;
	rt[++crt]=merge(T1,T2);
	return res;
}
inline void ouput(int q)
{
	puts("__________");
	rep(1,cnt,i)
	{
		printf("%d : %d %d %d\n",i,t[i].l,t[i].r,t[i].siz);
	}
	printf("%d %d\n",rt[q],q);
	puts("__________\n");
}
int main()
{
	srand(time(0));
	int n=read();rep(1,n,i)
	{
		int typ=read(),ope=read(),q=read();
		switch(ope)
		{
			case 1: ins(rt[typ],q);break;
			case 2: del(rt[typ],q);break;
			case 3: printf("%d\n",rnk(rt[typ],q));break;
			case 4: printf("%d\n",kth(rt[typ],q));break;
			case 5: printf("%d\n",pre(rt[typ],q));break;
			case 6: printf("%d\n",suc(rt[typ],q));break;
		}
//		ouput(typ);
	}
//	printf("\n%d",rt[4]);
}
